import React from 'react';
import { renderToStaticMarkup } from 'react-dom/server';
function Demo() {
  const callback = React.useCallback(() => 2 * 3, []);
  const value = React.useMemo(() => 2 * 3, []);
  return React.createElement('p', null, `${callback()}:${value}`);
}
const html = renderToStaticMarkup(React.createElement(Demo));
if (html !== '<p>6:6</p>') throw new Error(html);
